const email = $input.first().json;
const messageId = email.id || 'no-id';

// ── STEP 1: DUPLICATE CHECK FIRST ──
const processed = $input.all();
const isDuplicate = processed.filter(i => i.json.id === messageId).length > 1;
if (isDuplicate) {
  return [];
}

// ── STEP 2: EXTRACT RAW FIELDS ──
const senderEmail = email.From || email.from || email.sender || 'unknown@unknown.com';
const subjectLine = email.Subject || email.subject || 'No Subject';
const emailBody = email.snippet || email.text || email.body || '';
const fullText = subjectLine + ' ' + emailBody;
const emailOnly = senderEmail.replace(/.*<(.+)>/, '$1').trim();
const domain = emailOnly.includes('@') 
  ? emailOnly.split('@')[1].split('.')[0] 
  : 'Unknown';

// ── STEP 3: EXTRACT COMPANY ──
const companyMatch = fullText.match(/\b(?:at|to)\s+([A-Z][a-zA-Z0-9]+)\b/);
const companyFromText = companyMatch ? companyMatch[1].trim() : null;
const companyFromDomain = domain.charAt(0).toUpperCase() + domain.slice(1);
const company = companyFromText || companyFromDomain;

// ── STEP 4: EXTRACT ROLE ──
const roleMatch = fullText.match(/(?:for(?:\s+the)?(?:\s+role(?:\s+of)?)?|position(?:\s+of)?)\s+([A-Za-z\s]+(?:intern|engineer|analyst|developer|manager|designer|scientist|trainee|specialist)(?:\s+[A-Za-z]+)?)\s*(?:at|to|,|$)/i);
const jobRole = roleMatch ? roleMatch[1].trim() : 'Not Specified';

const today = new Date().toISOString().split('T')[0];

// ── STEP 5: RETURN DATA ──
return [{
  json: {
    company: company,
    role: jobRole,
    date: today,
    subject: subjectLine,
    sender: emailOnly,
    messageId: messageId,
    alertSent: 'Yes',
    matchScore: 'AI Pending'
  }
}];

